namespace {

constexpr int kBlockSize = 256;
constexpr size_t kStaticChunkSize = 4096;

int g_default_launch_blocks = 1;
int g_active_launch_blocks = 1;

unsigned char* g_device_raw = nullptr;
void* g_partial_a = nullptr;
void* g_partial_b = nullptr;

inline int max_int(int a, int b) { return a > b ? a : b; }

inline int launch_blocks_for_len(size_t len) {
  size_t needed = (len + kBlockSize - 1) / kBlockSize;
  if (needed == 0) needed = 1;
  size_t active = static_cast<size_t>(max_int(g_active_launch_blocks, 1));
  return static_cast<int>(needed < active ? needed : active);
}

template <typename T>
__device__ __forceinline__ T madd_square(T t, T f) {
  return t * t + f;
}

template <typename T, unsigned int compute_iterations>
__global__ void bench_kernel(T* src, T* partial, size_t len) {
  __shared__ T sdata[kBlockSize];

  const unsigned int tid = threadIdx.x;
  const size_t global_tid = static_cast<size_t>(blockIdx.x) * blockDim.x + tid;
  const size_t stride = static_cast<size_t>(blockDim.x) * gridDim.x;

  T local = 0;

  for (size_t idx = global_tid; idx < len; idx += stride) {
    const size_t base = (idx / kStaticChunkSize) * kStaticChunkSize;

    const T f0 = src[base + 0];
    const T f1 = src[base + 1];
    const T f2 = src[base + 2];
    const T f3 = src[base + 3];
    const T f4 = src[base + 4];
    const T f5 = src[base + 5];
    const T f6 = src[base + 6];
    const T f7 = src[base + 7];

    const T v = src[idx];

    T t0 = v, t1 = v, t2 = v, t3 = v, t4 = v, t5 = v, t6 = v, t7 = v;

    for (unsigned int j = 0; j < compute_iterations / 8; ++j) {
      t0 = madd_square(t0, f0);
      t1 = madd_square(t1, f1);
      t2 = madd_square(t2, f2);
      t3 = madd_square(t3, f3);
      t4 = madd_square(t4, f4);
      t5 = madd_square(t5, f5);
      t6 = madd_square(t6, f6);
      t7 = madd_square(t7, f7);
    }

    if ((compute_iterations % 8) > 0) t0 = madd_square(t0, f0);
    if ((compute_iterations % 8) > 1) t1 = madd_square(t1, f1);
    if ((compute_iterations % 8) > 2) t2 = madd_square(t2, f2);
    if ((compute_iterations % 8) > 3) t3 = madd_square(t3, f3);
    if ((compute_iterations % 8) > 4) t4 = madd_square(t4, f4);
    if ((compute_iterations % 8) > 5) t5 = madd_square(t5, f5);
    if ((compute_iterations % 8) > 6) t6 = madd_square(t6, f6);

    local += (t0 + t1 + t2 + t3 + t4 + t5 + t6 + t7);
  }

  sdata[tid] = local;
  __syncthreads();

  for (unsigned int offset = kBlockSize / 2; offset > 0; offset >>= 1) {
    if (tid < offset) {
      sdata[tid] += sdata[tid + offset];
    }
    __syncthreads();
  }

  if (tid == 0) {
    partial[blockIdx.x] = sdata[0];
  }
}

template <typename T>
__global__ void reduce_kernel(const T* in, T* out, size_t len) {
  __shared__ T sdata[kBlockSize];

  const unsigned int tid = threadIdx.x;
  const size_t global_tid = static_cast<size_t>(blockIdx.x) * blockDim.x + tid;
  const size_t stride = static_cast<size_t>(blockDim.x) * gridDim.x;

  T local = 0;

  for (size_t idx = global_tid; idx < len; idx += stride) {
    local += in[idx];
  }

  sdata[tid] = local;
  __syncthreads();

  for (unsigned int offset = kBlockSize / 2; offset > 0; offset >>= 1) {
    if (tid < offset) {
      sdata[tid] += sdata[tid + offset];
    }
    __syncthreads();
  }

  if (tid == 0) {
    out[blockIdx.x] = sdata[0];
  }
}

template <typename Element, unsigned int compute_iterations>
size_t bench(size_t len, const Element seed1, const Element seed2, Element* src) {
  (void)seed1;
  (void)seed2;

  Element* partial_a = reinterpret_cast<Element*>(g_partial_a);
  Element* partial_b = reinterpret_cast<Element*>(g_partial_b);

  int blocks = launch_blocks_for_len(len);
  bench_kernel<Element, compute_iterations><<<blocks, kBlockSize>>>(src, partial_a, len);
  CUDA_SAFE_CALL(cudaGetLastError());

  size_t current_len = static_cast<size_t>(blocks);
  Element* in = partial_a;
  Element* out = partial_b;

  while (current_len > 1) {
    int reduce_blocks = launch_blocks_for_len(current_len);
    reduce_kernel<Element><<<reduce_blocks, kBlockSize>>>(in, out, current_len);
    CUDA_SAFE_CALL(cudaGetLastError());
    current_len = static_cast<size_t>(reduce_blocks);
    Element* tmp = in;
    in = out;
    out = tmp;
  }

  CUDA_SAFE_CALL(cudaMemcpyAsync(src, in, sizeof(Element), cudaMemcpyDeviceToDevice));
  return len;
}

template <typename Op>
double measure_operation(Op op) {
  cudaEvent_t start, stop;
  CUDA_SAFE_CALL(cudaEventCreate(&start));
  CUDA_SAFE_CALL(cudaEventCreate(&stop));

  CUDA_SAFE_CALL(cudaEventRecord(start));
  op();
  CUDA_SAFE_CALL(cudaEventRecord(stop));
  CUDA_SAFE_CALL(cudaEventSynchronize(stop));

  float ms = 0.0f;
  CUDA_SAFE_CALL(cudaEventElapsedTime(&ms, start, stop));

  CUDA_SAFE_CALL(cudaEventDestroy(start));
  CUDA_SAFE_CALL(cudaEventDestroy(stop));

  return static_cast<double>(ms);
}

auto runbench_warmup(void* c, size_t size) {
  const int num_elements = static_cast<int>(size / sizeof(double));
  double* ptr = reinterpret_cast<double*>(c);

  const double ms = measure_operation([&] {
    bench<double, 16>(num_elements, 1.0, -1.0, ptr);
  });

  return static_cast<long long>(ms * 1000.0);
}

template <typename Op>
auto benchmark_cuda(Op op) {
  constexpr int total_runs = 20;
  constexpr int total_half_thread_runs = 10;

  auto duration = op();
  std::vector<decltype(duration)> measurements;

  g_active_launch_blocks = g_default_launch_blocks;

  for (int i = 1; i < total_runs; i++) {
    duration = op();
    measurements.push_back(duration);
  }

  if (g_default_launch_blocks > 1) {
    g_active_launch_blocks = g_default_launch_blocks / 2;
    if (g_active_launch_blocks < 1) g_active_launch_blocks = 1;

    for (int i = 1; i < total_half_thread_runs; i++) {
      duration = op();
      measurements.push_back(duration);
    }
  }

  g_active_launch_blocks = g_default_launch_blocks;

  return *std::min_element(measurements.begin(), measurements.end());
}

class ComputeSpace {
  size_t memory_space_{0};
  int compute_iterations_{0};

 public:
  ComputeSpace(size_t memory_space, int compute_iterations)
      : memory_space_{memory_space}, compute_iterations_{compute_iterations} {}

  template <typename T>
  size_t compute_ops() const {
    const auto total_elements = element_count<T>();
    const long long computations =
        total_elements * compute_iterations_ * 2 * 1 + total_elements - 1;
    return static_cast<size_t>(computations);
  }

  size_t memory_traffic() const { return memory_space_; }

  template <typename T>
  size_t element_count() const {
    return memory_space_ / sizeof(T);
  }
};

template <unsigned int compute_iterations>
void runbench(void* c, size_t size) {
  ComputeSpace cs{size, static_cast<int>(compute_iterations)};

  float* c_as_float = reinterpret_cast<float*>(c);
  auto kernel_time_mad_sp = benchmark_cuda([&] {
    return measure_operation([&] {
      bench<float, compute_iterations>(cs.element_count<float>(), 1.f, -1.f,
                                       c_as_float);
    });
  });

  double* c_as_double = reinterpret_cast<double*>(c);
  auto kernel_time_mad_dp = benchmark_cuda([&] {
    return measure_operation([&] {
      bench<double, compute_iterations>(cs.element_count<double>(), 1.0, -1.0,
                                        c_as_double);
    });
  });

  int* c_as_int = reinterpret_cast<int*>(c);
  auto kernel_time_mad_int = benchmark_cuda([&] {
    return measure_operation([&] {
      bench<int, compute_iterations>(cs.element_count<int>(), 1, -1, c_as_int);
    });
  });

  const auto computations_sp = cs.compute_ops<float>();
  const auto computations_dp = cs.compute_ops<double>();
  const auto computations_int = cs.compute_ops<int>();
  const auto memory_traffic = cs.memory_traffic();

  const auto setw = std::setw;
  const auto setprecision = std::setprecision;
  std::cout << std::fixed << "         " << std::setw(4) << compute_iterations
            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_sp) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_sp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_sp) / kernel_time_mad_sp *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_sp *
                   1000. / (1000. * 1000. * 1000.)

            << ",   " << setw(8) << setprecision(3)
            << static_cast<double>(computations_dp) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_dp << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_dp) / kernel_time_mad_dp *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_dp *
                   1000. / (1000. * 1000. * 1000.)

            << ",  " << setw(8) << setprecision(3)
            << static_cast<double>(computations_int) /
                   static_cast<double>(memory_traffic)
            << "," << setw(8) << setprecision(2) << kernel_time_mad_int << ","
            << setw(8) << setprecision(2)
            << static_cast<double>(computations_int) / kernel_time_mad_int *
                   1000. / static_cast<double>(1000 * 1000 * 1000)
            << "," << setw(7) << setprecision(2)
            << static_cast<double>(memory_traffic) / kernel_time_mad_int *
                   1000. / (1000. * 1000. * 1000.)

            << std::endl;
}

template <unsigned int compute_iterations>
void runbench_range(void* cd, size_t size) {
  runbench<compute_iterations>(cd, size);
}

template <unsigned int j1, unsigned int j2, unsigned int... Args>
void runbench_range(void* cd, size_t size) {
  runbench_range<j1>(cd, size);
  runbench_range<j2, Args...>(cd, size);
}

