extern "C" void mixbenchGPU(double* c, long size) {
  const size_t size_bytes = static_cast<size_t>(size) * sizeof(double);

  cudaDeviceProp device_prop = GetDeviceProperties();
  g_default_launch_blocks = max_int(1, device_prop.multiProcessorCount * 32);
  g_active_launch_blocks = g_default_launch_blocks;

  const size_t max_elements = size_bytes / sizeof(int);
  const int max_blocks = launch_blocks_for_len(max_elements);

  CUDA_SAFE_CALL(cudaMalloc(reinterpret_cast<void**>(&g_device_raw), size_bytes));
  CUDA_SAFE_CALL(cudaMalloc(&g_partial_a, static_cast<size_t>(max_blocks) * sizeof(double)));
  CUDA_SAFE_CALL(cudaMalloc(&g_partial_b, static_cast<size_t>(max_blocks) * sizeof(double)));
  CUDA_SAFE_CALL(cudaMemset(g_device_raw, 0, size_bytes));

  std::cout << "--------------------------------------------"
               "-------------- CSV data "
               "--------------------------------------------"
               "--------------"
            << std::endl;
  std::cout << "Experiment ID, Single Precision ops,,,,              Double "
               "precision ops,,,,              Integer operations,,, "
            << std::endl;
  std::cout << "Compute iters, Flops/byte, ex.time,  GFLOPS, GB/sec, "
               "Flops/byte, ex.time,  GFLOPS, GB/sec, Iops/byte, ex.time,   "
               "GIOPS, GB/sec"
            << std::endl;

  runbench_warmup(g_device_raw, size_bytes);

  runbench_range<0, 1, 2, 3, 4, 6, 8, 12, 16, 20, 24, 28, 32, 40, 6 * 8, 7 * 8,
                 8 * 8, 10 * 8, 13 * 8, 15 * 8, 16 * 8, 20 * 8, 24 * 8, 32 * 8,
                 40 * 8, 64 * 8>(g_device_raw, size_bytes);

  std::cout << "---------------------------------------------------------------"
               "---------------------------------------------------------------"
            << std::endl;

  CUDA_SAFE_CALL(cudaMemcpy(c, g_device_raw, size_bytes, cudaMemcpyDeviceToHost));

  CUDA_SAFE_CALL(cudaFree(g_partial_b));
  CUDA_SAFE_CALL(cudaFree(g_partial_a));
  CUDA_SAFE_CALL(cudaFree(g_device_raw));

  g_partial_b = nullptr;
  g_partial_a = nullptr;
  g_device_raw = nullptr;
}
